export const checkId = 'dynamic-port';
export const name = 'Dynamic Port Configuration';
export const appliesTo = ['deployable', 'server', 'framework'];

const DYNAMIC_PATTERNS = [
  /process\.env\.PORT\b/,
  /process\.env\['PORT'\]/,
  /process\.env\["PORT"\]/,
  /\benv\.PORT\b/,
  /import\.meta\.env\.PORT\b/,
  /Deno\.env\.get\(['"]PORT['"]\)/,
  /Bun\.env\.PORT\b/,
  /const\s*\{\s*PORT\s*\}\s*=\s*process\.env/,
  /let\s*\{\s*PORT\s*\}\s*=\s*process\.env/,
  /var\s*\{\s*PORT\s*\}\s*=\s*process\.env/,
  /PORT\s*=\s*process\.env/,
  /listen\s*\(\s*(?:process\.env\.PORT|env\.PORT|Deno\.env|Bun\.env|import\.meta\.env\.PORT)/,
];

const HARDCODED_PATTERNS = [
  /\.listen\s*\(\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
  /\.listen\s*\(\s*\{[^}]*port\s*:\s*(3000|3001|8080|8081|5000|5001|8000|9000|4000|4200)\b/,
];

const FALLBACK_PATTERNS = [
  /(?:Number|parseInt)?\s*\(?\s*process\.env\.PORT\s*\)?\s*(?:\|\||\?\?)\s*\d+/,
  /\{\s*PORT\s*=\s*\d+\s*\}\s*=\s*process\.env/,
];

const NON_PROD_PATHS = [
  /(?:^|\/)examples?\//,
  /(?:^|\/)demo\//,
  /(?:^|\/)demos\//,
  /(?:^|\/)test\//,
  /(?:^|\/)__tests__\//,
  /(?:^|\/)spec\//,
  /(?:^|\/)benchmark\//,
  /(?:^|\/)perf\//,
  /(?:^|\/)docs\//,
  /(?:^|\/)fixture\//,
  /(?:^|\/)fixtures\//,
  /(?:^|\/)playground\//,
  /(?:^|\/)playgrounds\//,
  /(?:^|\/)sandbox\//,
  /(?:^|\/)stub\//,
  /(?:^|\/)stubs\//,
  /(?:^|\/)mock\//,
  /(?:^|\/)mocks\//,
  /(?:^|\/)e2e\//,
  /(?:^|\/)cypress\//,
  /(?:^|\/)playwright\//,
  /(?:^|\/)storybook\//,
  /(?:^|\/)stories\//,
  /(?:^|\/)coverage\//,
  /(?:^|\/)jest\//,
  /(?:^|\/)vitest\//,
  /\.github\//,
];

const SERVER_DEPS = [
  'express', 'fastify', 'koa', 'hono', 'polka', 'restify', 'connect', 'sirv',
  'http-server', 'serve', 'serve-static', 'micro', 'nestjs', '@nestjs/core',
  'next', 'nuxt', 'astro', 'remix', 'gatsby', 'nitropack', 'nuxi', 'h3',
  'solid-start', '@solidjs/start',
];

function isNonProductionPath(filePath) {
  return NON_PROD_PATHS.some(p => p.test(filePath));
}

function isFrameworkSource(tree, packageJson, repoType) {
  const pkgCount = tree.filter(p => /^packages\/[^/]+\/package\.json$/.test(p)).length;
  const hasExamples = tree.some(p => /^(examples?|demos?|playground|playgrounds|fixtures?|test\/fixtures)\/[^/]+/.test(p));
  const hasApps = tree.some(p => /^apps\/[^/]+/.test(p));
  const hasWorkspaces = !!packageJson?.workspaces || tree.some(p => /^pnpm-workspace\.ya?ml$/.test(p));
  const isPrivate = packageJson?.private === true;
  const hasRootDeploy = tree.some(p => /^(Dockerfile|docker-compose|Procfile|fly\.toml|render\.yaml|vercel\.json|netlify\.toml|app\.yaml|wrangler\.toml)/.test(p));

  if (pkgCount >= 2 && !hasApps && !hasRootDeploy && (hasExamples || hasWorkspaces) && isPrivate) {
    return true;
  }
  if (pkgCount >= 2 && !hasApps && !hasRootDeploy && hasWorkspaces) {
    return true;
  }

  if (!hasApps && !hasRootDeploy && hasExamples && packageJson) {
    const scripts = packageJson.scripts || {};
    const hasServerRunScript = ['start', 'serve'].some(s =>
      scripts[s] && /node|ts-node|nodemon|pm2/.test(scripts[s])
    );
    if (!hasServerRunScript) {
      const hasMain = !!packageJson.main;
      const keywords = packageJson.keywords || [];
      const hasLibKw = keywords.some(k => /framework|library|middleware|plugin|toolkit/.test(k));
      if ((repoType === 'framework' || repoType === 'library') && (hasMain || hasLibKw)) {
        return true;
      }
    }
  }

  return false;
}

function looksLikeLibrary(packageJson, tree) {
  if (!packageJson) return false;
  const scripts = packageJson.scripts || {};
  if (scripts.start || scripts.serve) return false;

  const hasPages = tree.some(p => /^(src\/)?(app|pages|routes)\//.test(p));
  if (hasPages) return false;

  const main = packageJson.main || '';
  const module = packageJson.module || '';
  const hasDistMain = /\/(dist|lib|build|esm|cjs)\//.test(main) || /\/(dist|lib|build|esm|cjs)\//.test(module);

  const keywords = packageJson.keywords || [];
  const hasLibKw = keywords.some(k => /^(library|lib|component|plugin|tool|utils|helpers?|sdk|client|package)$/.test(k));

  if ((hasDistMain || packageJson.exports) && (hasLibKw || packageJson.bin) && !scripts.start) {
    return true;
  }

  return false;
}

function selectFilesToScan(tree, packageJson) {
  const candidates = new Map();

  if (packageJson?.main) candidates.set(packageJson.main, 0);
  if (packageJson?.bin) {
    if (typeof packageJson.bin === 'string') candidates.set(packageJson.bin, 0);
    else Object.values(packageJson.bin).forEach(v => { if (typeof v === 'string') candidates.set(v, 0); });
  }

  if (packageJson?.scripts) {
    for (const script of Object.values(packageJson.scripts)) {
      const refs = script.matchAll(/\b(?:node|ts-node|tsx|nodemon)\s+([^\s&|]+)/g);
      for (const [, ref] of refs) {
        if (ref && !ref.startsWith('-')) {
          candidates.set(ref, 1);
          candidates.set(`src/${ref}`, 2);
          candidates.set(`app/${ref}`, 2);
        }
      }
    }
  }

  for (const p of tree) {
    if (!/\.(js|ts|mjs|cjs)$/.test(p)) continue;
    if (/node_modules|\/dist\/|\/build\/|\.output\/|\.test\.|\.spec\.|__tests__\/|\.d\.ts$/.test(p)) continue;

    let priority = 100;
    const depth = p.split('/').filter(Boolean).length;

    if (/^(apps|services)\/[^/]+\/(src\/)?(index|server|app|main|cli|start|listen|run|handler|worker|api)\./.test(p)) priority = 1;
    else if (/^(apps|services)\/[^/]+\/(src\/)?/.test(p)) priority = 5;
    else if (/^(apps|services)\/[^/]+\//.test(p)) priority = 8;
    else if (/^(src|app|server|api|lib|bin)\/(index|server|app|main|cli|start|listen|run|handler|worker|api)\./.test(p)) priority = 2;
    else if (/^(src|app|server|api|lib|bin)\//.test(p)) priority = 6;
    else if (/^(index|server|app|main|cli|start|listen|run|handler|worker|api)\./.test(p)) priority = 3;
    else if (/^(config|configs)\//.test(p)) priority = 10;
    else if (/^(examples?|demos?|playground|playgrounds|fixtures?|test|tests|__tests__|docs|storybook)\//.test(p)) priority = 90;
    else priority = 20 + depth * 2;

    const filename = p.split('/').pop();
    if (/(server|listen|app|handler|worker|gateway|start|run|cli|api)\./.test(filename)) priority -= 3;

    if (!candidates.has(p) || candidates.get(p) > priority) {
      candidates.set(p, priority);
    }
  }

  return Array.from(candidates.entries())
    .filter(([p]) => tree.includes(p))
    .sort((a, b) => a[1] - b[1])
    .slice(0, 40)
    .map(([p]) => p);
}

async function scanDeploymentConfigs(tree, files) {
  const findings = [];
  const deployFiles = tree.filter(p =>
    /^(Dockerfile|docker-compose\.ya?ml|Procfile|fly\.toml|render\.yaml|vercel\.json|netlify\.toml|app\.yaml|heroku\.yml|wrangler\.toml)$/.test(p)
  );

  for (const p of deployFiles.slice(0, 10)) {
    try {
      const content = await files.get(p);
      if (!content) continue;
      if (/process\.env\.PORT|\$PORT|\bPORT=/.test(content)) {
        findings.push({ file: p, issue: 'Deployment config references PORT environment variable' });
      }
    } catch (e) {
      console.error(`[dynamic-port] Error reading deployment config ${p}:`, e);
    }
  }
  return findings;
}

function scanRootScripts(packageJson) {
  const findings = [];
  let hasDynamic = false;
  let hasHardcoded = false;

  if (!packageJson?.scripts) return { findings, hasDynamic, hasHardcoded };

  for (const [name, script] of Object.entries(packageJson.scripts)) {
    if (!script) continue;
    if (/process\.env\.PORT|\$PORT|\bPORT=/.test(script)) {
      hasDynamic = true;
      findings.push({ file: 'package.json', issue: `Script "${name}" uses PORT env var: ${script}` });
    }
    const match = script.match(/\b(?:listen\s*\()?(\d{4,5})\b/);
    if (match && ['3000', '3001', '8080', '8081', '5000', '5001', '8000', '9000', '4000', '4200'].includes(match[1])) {
      hasHardcoded = true;
      findings.push({ file: 'package.json', issue: `Script "${name}" references hardcoded port ${match[1]}: ${script}` });
    }
  }

  return { findings, hasDynamic, hasHardcoded };
}

async function scanWorkspaceScripts(tree, files) {
  const findings = [];
  let hasDynamic = false;
  let hasHardcoded = false;

  const pkgPaths = tree.filter(p =>
    p.endsWith('package.json') &&
    !p.includes('node_modules') &&
    p !== 'package.json'
  ).slice(0, 20);

  for (const p of pkgPaths) {
    try {
      const content = await files.get(p);
      if (!content) continue;
      const pkg = JSON.parse(content);
      if (!pkg?.scripts) continue;

      for (const [name, script] of Object.entries(pkg.scripts)) {
        if (!script) continue;
        if (/process\.env\.PORT|\$PORT|\bPORT=/.test(script)) {
          hasDynamic = true;
          findings.push({ file: p, issue: `Script "${name}" uses PORT env var: ${script}` });
        }
        const match = script.match(/\b(?:listen\s*\()?(\d{4,5})\b/);
        if (match && ['3000', '3001', '8080', '8081', '5000', '5001', '8000', '9000', '4000', '4200'].includes(match[1])) {
          hasHardcoded = true;
          findings.push({ file: p, issue: `Script "${name}" references hardcoded port ${match[1]}: ${script}` });
        }
      }
    } catch (e) {
      console.error(`[dynamic-port] Error scanning scripts in ${p}:`, e);
    }
  }

  return { findings, hasDynamic, hasHardcoded };
}

async function scanCodeFiles(fileList, files) {
  let hasDynamic = false;
  let hasHardcoded = false;
  let hasFallback = false;
  const findings = [];
  const seen = new Set();

  for (const filePath of fileList) {
    let content;
    try {
      content = await files.get(filePath);
    } catch (e) {
      console.error(`[dynamic-port] Error reading ${filePath}:`, e);
      continue;
    }
    if (!content) continue;

    const lines = content.split('\n');
    const isNonProd = isNonProductionPath(filePath);

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const trimmed = line.trim();
      if (trimmed.startsWith('//') || trimmed.startsWith('/*') || trimmed.startsWith('*') || trimmed.startsWith('#')) continue;

      for (const pattern of DYNAMIC_PATTERNS) {
        if (pattern.test(line)) {
          hasDynamic = true;
          const key = `${filePath}:${i}:dynamic`;
          if (!seen.has(key)) {
            seen.add(key);
            findings.push({ file: filePath, line: i + 1, issue: 'Uses dynamic port (process.env.PORT or equivalent)' });
          }
        }
      }

      for (const pattern of HARDCODED_PATTERNS) {
        const match = line.match(pattern);
        if (match) {
          const port = match[1];
          if (isNonProd) {
            findings.push({ file: filePath, line: i + 1, issue: `Hardcoded port in non-production code: ${port}` });
          } else {
            hasHardcoded = true;
            findings.push({ file: filePath, line: i + 1, issue: `Hardcoded port: ${port}` });
          }
        }
      }

      for (const pattern of FALLBACK_PATTERNS) {
        if (pattern.test(line)) {
          if (isNonProd) {
            findings.push({ file: filePath, line: i + 1, issue: 'Fallback hardcoded port in non-production code' });
          } else {
            hasFallback = true;
            findings.push({ file: filePath, line: i + 1, issue: 'Uses dynamic port with fallback default' });
          }
        }
      }
    }
  }

  return { hasDynamic, hasHardcoded, hasFallback, findings };
}

function hasServerDependencies(packageJson) {
  if (!packageJson) return false;
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies };
  return SERVER_DEPS.some(d => deps[d]);
}

async function detectFrameworkApp(tree, files, rootPkg) {
  function checkPkg(pkg, pkgDir) {
    if (!pkg) return null;
    const scripts = pkg.scripts || {};
    const scriptStr = Object.values(scripts).join(' ');
    const prefix = pkgDir ? pkgDir + '/' : '';

    if (['next.config.js', 'next.config.ts', 'next.config.mjs'].some(f => tree.includes(prefix + f))) return 'Next.js';
    if (['nuxt.config.ts', 'nuxt.config.js', 'nuxt.config.mjs'].some(f => tree.includes(prefix + f))) return 'Nuxt';
    if (['astro.config.mjs', 'astro.config.js', 'astro.config.ts'].some(f => tree.includes(prefix + f))) return 'Astro';
    if (['remix.config.js', 'remix.config.ts', 'remix.config.mjs'].some(f => tree.includes(prefix + f))) return 'Remix';
    if (['gatsby-config.js', 'gatsby-config.ts', 'gatsby-config.mjs'].some(f => tree.includes(prefix + f))) return 'Gatsby';

    const svelteConfigs = ['svelte.config.js', 'svelte.config.ts', 'svelte.config.mjs'];
    if (svelteConfigs.some(f => tree.includes(prefix + f))) {
      if (tree.some(p => p.startsWith(prefix + 'src/routes/')) || tree.some(p => p.startsWith(prefix + 'src/app.html')) || /svelte-kit/.test(scriptStr)) {
        return 'SvelteKit';
      }
    }

    if (/\bnext\b/.test(scriptStr)) return 'Next.js';
    if (/\bnuxt\b/.test(scriptStr)) return 'Nuxt';
    if (/\bastro\b/.test(scriptStr)) return 'Astro';
    if (/\bremix\b/.test(scriptStr)) return 'Remix';
    if (/\bgatsby\b/.test(scriptStr)) return 'Gatsby';
    if (/svelte-kit/.test(scriptStr)) return 'SvelteKit';

    const deps = { ...pkg.dependencies, ...pkg.devDependencies };
    if (deps['next']) return 'Next.js';
    if (deps['nuxt'] || deps['nuxt3'] || deps['nuxi']) return 'Nuxt';
    if (deps['astro']) return 'Astro';
    if (deps['gatsby']) return 'Gatsby';
    if (deps['remix']) return 'Remix';

    return null;
  }

  const rootFw = checkPkg(rootPkg, '');
  if (rootFw) return { framework: rootFw, source: 'package.json' };

  const pkgPaths = tree.filter(p =>
    p.endsWith('package.json') &&
    !p.includes('node_modules') &&
    p !== 'package.json'
  ).slice(0, 20);

  for (const p of pkgPaths) {
    try {
      const content = await files.get(p);
      if (!content) continue;
      const pkg = JSON.parse(content);
      const dir = p.replace(/\/package\.json$/, '');
      const fw = checkPkg(pkg, dir);
      if (fw) return { framework: fw, source: p };
    } catch (e) {
      console.error(`[dynamic-port] Error checking framework in ${p}:`, e);
    }
  }

  return null;
}

export async function check(context) {
  const { tree, files, packageJson, repoType, owner, repo } = context;

  try {
    if (repoType === 'empty' || tree.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repository — no server port needed', findings: [] };
    }

    const hasCodeFiles = tree.some(p => /\.(js|ts|mjs|cjs)$/.test(p) && !p.includes('node_modules'));
    if (!hasCodeFiles) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'No JavaScript/TypeScript files found — port configuration not applicable', findings: [] };
    }

    if (isFrameworkSource(tree, packageJson, repoType)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Framework or library source repository — not deployed as a standalone application', findings: [] };
    }

    if (looksLikeLibrary(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or tool detected — no server port needed', findings: [] };
    }

    const filesToScan = selectFilesToScan(tree, packageJson);
    const deployFindings = await scanDeploymentConfigs(tree, files);
    const codeResults = await scanCodeFiles(filesToScan, files);
    const rootScriptResults = scanRootScripts(packageJson);
    const workspaceScriptResults = await scanWorkspaceScripts(tree, files);
    const fwApp = await detectFrameworkApp(tree, files, packageJson);

    const allFindings = [
      ...deployFindings,
      ...codeResults.findings,
      ...rootScriptResults.findings,
      ...workspaceScriptResults.findings,
    ];

    const hasDynamic = codeResults.hasDynamic || rootScriptResults.hasDynamic || workspaceScriptResults.hasDynamic || deployFindings.length > 0;
    const hasHardcoded = codeResults.hasHardcoded || rootScriptResults.hasHardcoded || workspaceScriptResults.hasHardcoded;
    const hasFallback = codeResults.hasFallback;

    if (hasDynamic || hasFallback) {
      return { checkId, status: 'pass', confidence: 'high', message: 'Dynamic port configuration found (process.env.PORT or equivalent)', findings: allFindings };
    }

    if (hasHardcoded) {
      return { checkId, status: 'fail', confidence: 'high', message: 'Hardcoded port detected — should use process.env.PORT', findings: allFindings };
    }

    if (fwApp) {
      return { checkId, status: 'pass', confidence: 'high', message: `${fwApp.framework} app detected — framework handles dynamic port via PORT env var`, findings: allFindings };
    }

    const hasServerIndicator = hasServerDependencies(packageJson) ||
      filesToScan.some(p => /(server|listen|app|handler|worker|gateway|start|run|cli|api)\./.test(p.split('/').pop())) ||
      tree.some(p => /^(Dockerfile|docker-compose|Procfile|fly\.toml|render\.yaml|vercel\.json|netlify\.toml)/.test(p));

    if (!hasServerIndicator) {
      return { checkId, status: 'not-applicable', confidence: 'medium', message: 'No server runtime or deployment configuration detected', findings: allFindings };
    }

    return { checkId, status: 'check-it', confidence: 'medium', message: 'Server runtime detected but no explicit port configuration found — verify PORT env var is supported', findings: allFindings };

  } catch (err) {
    console.error(`[dynamic-port] Analysis failed for ${owner}/${repo}:`, err);
    return { checkId, status: 'check-it', confidence: 'low', message: `Analysis error: ${err.message}`, findings: [] };
  }
}
